export function searchMilitaryJobs(query: string, branch?: string): MilitaryJobCode[] {
  if (!query.trim() && !branch) return militaryJobCodes.slice(0, 50);

  const lowerQuery = query.toLowerCase();
  return militaryJobCodes.filter(job => {
    const matchesBranch = !branch || job.branch === branch;
    const matchesQuery = !query.trim() ||
      job.code.toLowerCase().includes(lowerQuery) ||
      job.title.toLowerCase().includes(lowerQuery) ||
      job.category.toLowerCase().includes(lowerQuery) ||
      job.keywords.some(kw => kw.toLowerCase().includes(lowerQuery));
    return matchesBranch && matchesQuery;
  }).slice(0, 50);
}

export function getHazardsForMOS(code: string): string[] {
  const job = militaryJobCodes.find(j => j.code.toUpperCase() === code.toUpperCase());
  return job?.commonHazards || [];
}

export function getCodeTypeForBranch(branch: string): string {
  switch (branch) {
    case 'Army': return 'MOS';
    case 'Marines': return 'MOS';
    case 'Air Force': return 'AFSC';
    case 'Space Force': return 'AFSC';
    case 'Navy': return 'Rating';
    case 'Coast Guard': return 'Rating';
    default: return 'Code';
  }
}

export function formatMOSDisplay(job: MilitaryJobCode): string {
  return `${job.code} - ${job.title}`;
}
